306→interface BranchDiffViewProps {
307→  repoPath: string;
308→  branch: string;
309→}
310→
311→export function BranchDiffView({ repoPath, branch }: BranchDiffViewProps) {
312→  const { data: files, isLoading, error } = useBranchDiffQuery(repoPath, branch);
313→
314→  if (isLoading) {
315→    return (
316→      <div className="flex items-center justify-center p-20">
317→        <Loader2 size={20} className="animate-spin text-fg-subtle" />
318→      </div>
319→    );
320→  }
321→
322→  if (error) {
323→    return (
324→      <div className="p-8">
325→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
326→          <p className="text-sm text-fg-muted">Failed to load branch diff</p>
327→          <p className="mt-1 text-xs text-fg-subtle">
328→            {error instanceof Error ? error.message : "Unknown error"}
329→          </p>
330→        </div>
331→      </div>
332→    );
333→  }
334→
335→  if (!files || files.length === 0) {
336→    return (
337→      <div className="p-8">
338→        <div className="rounded-lg border border-border-subtle bg-bg-overlay p-6 text-center">
339→          <p className="text-sm text-fg-muted">No changes on this branch</p>
340→          <p className="mt-1 text-xs text-fg-subtle">
341→            This branch has no differences from the default branch
342→          </p>
343→        </div>
344→      </div>
345→    );
346→  }
347→
348→  return (
349→    <DiffFileList
350→      files={files}
351→      summaryLabel={branch}
352→      summaryDetail="All changes on branch"
353→    />
354→  );
355→}
