  1→import { useState, useEffect } from "react";
  2→import { Sidebar } from "./features/repos/Sidebar";
  3→import { TitleBar } from "./components/TitleBar";
  4→import { TabBar } from "./components/TabBar";
  5→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  6→import { TranscriptView } from "./features/transcripts/TranscriptView";
  7→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
  8→import { TerminalPanel } from "./features/terminal/TerminalPanel";
  9→import { useLiveUpdates } from "./hooks/use-live-updates";
 10→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 11→import { ArrowLeft, GitCommit } from "lucide-react";
 12→
 13→export interface Tab {
 14→  id: string;
 15→  branch: string;
 16→  repoPath: string;
 17→  worktree: WorktreeInfo | null;
 18→  hasActiveSession: boolean;
 19→}
 20→
 21→export default function App() {
 22→  const [tabs, setTabs] = useState<Tab[]>([
 23→    {
 24→      id: "main",
 25→      branch: "main",
 26→      repoPath: "",
 27→      worktree: null,
 28→      hasActiveSession: false,
 29→    },
 30→  ]);
 31→  const [activeTabId, setActiveTabId] = useState("main");
 32→  const [terminalHeight, setTerminalHeight] = useState(
 33→    () => Number(localStorage.getItem("entire:terminal-height")) || 220
 34→  );
 35→  const [isTerminalOpen, setIsTerminalOpen] = useState(
 36→    () => localStorage.getItem("entire:terminal-open") !== "false"
 37→  );
 38→  const [innerTab, setInnerTab] = useState<"checkpoints" | "diff">(
 39→    "checkpoints"
 40→  );
 41→  const [selectedCheckpoint, setSelectedCheckpoint] =
 42→    useState<CheckpointSummary | null>(null);
 43→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 44→    "transcript" | "diff"
 45→  >("transcript");
 46→
 47→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
 48→
 49→  // Live updates — watch active repo for checkpoint/session changes
 50→  useLiveUpdates(activeTab.repoPath);
 51→
 52→  // Persist UI state to localStorage
 53→  useEffect(() => {
 54→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
 55→  }, [terminalHeight]);
 56→  useEffect(() => {
 57→    localStorage.setItem("entire:terminal-open", String(isTerminalOpen));
 58→  }, [isTerminalOpen]);
 59→
 60→  // Clear selected checkpoint when switching branch tabs
 61→  useEffect(() => {
 62→    setSelectedCheckpoint(null);
 63→    setCheckpointInnerTab("transcript");
 64→  }, [activeTabId]);
 65→
 66→  // Keyboard shortcuts
 67→  useEffect(() => {
 68→    function onKeyDown(e: KeyboardEvent) {
 69→      const meta = e.metaKey || e.ctrlKey;
 70→
 71→      // Cmd+K = focus search
 72→      if (meta && e.key === "k") {
 73→        e.preventDefault();
 74→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
 75→      }
 76→      // Ctrl+` = toggle terminal
 77→      if (e.ctrlKey && e.key === "`") {
 78→        e.preventDefault();
 79→        setIsTerminalOpen((v) => !v);
 80→      }
 81→      // Cmd+W = close active tab
 82→      if (meta && e.key === "w") {
 83→        e.preventDefault();
 84→        handleCloseTab(activeTabId);
 85→      }
 86→      // Cmd+1-9 = switch to tab by index
 87→      if (meta && e.key >= "1" && e.key <= "9") {
 88→        e.preventDefault();
 89→        const idx = parseInt(e.key) - 1;
 90→        if (idx < tabs.length) {
 91→          setActiveTabId(tabs[idx].id);
 92→        }
 93→      }
 94→      // Cmd+[ / Cmd+] = prev/next tab
 95→      if (meta && e.key === "[") {
 96→        e.preventDefault();
 97→        const idx = tabs.findIndex((t) => t.id === activeTabId);
 98→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
 99→      }
100→      if (meta && e.key === "]") {
101→        e.preventDefault();
102→        const idx = tabs.findIndex((t) => t.id === activeTabId);
103→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
104→      }
105→      // Escape = deselect checkpoint
106→      if (e.key === "Escape" && selectedCheckpoint) {
107→        setSelectedCheckpoint(null);
108→      }
109→    }
110→    window.addEventListener("keydown", onKeyDown);
111→    return () => window.removeEventListener("keydown", onKeyDown);
112→  }, [activeTabId, tabs, selectedCheckpoint]);
113→
114→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
115→    const existing = tabs.find(
116→      (t) => t.branch === branch.name && t.repoPath === repoPath
117→    );
118→    if (existing) {
119→      setActiveTabId(existing.id);
120→    } else {
121→      const newTab: Tab = {
122→        id: `${repoPath}:${branch.name}`,
123→        branch: branch.name,
124→        repoPath,
125→        worktree: null,
126→        hasActiveSession: false,
127→      };
128→      setTabs([...tabs, newTab]);
129→      setActiveTabId(newTab.id);
130→    }
131→  }
132→
133→  function handleWorktreeSelect(wt: WorktreeInfo, repoPath: string) {
134→    const existing = tabs.find(
135→      (t) => t.branch === wt.branch && t.repoPath === repoPath
136→    );
137→    if (existing) {
138→      setActiveTabId(existing.id);
139→    } else {
140→      const newTab: Tab = {
141→        id: `${repoPath}:${wt.branch}`,
142→        branch: wt.branch,
143→        repoPath,
144→        worktree: wt,
145→        hasActiveSession: false,
146→      };
147→      setTabs([...tabs, newTab]);
148→      setActiveTabId(newTab.id);
149→    }
150→  }
151→
152→  function handleCloseTab(tabId: string) {
153→    if (tabs.length <= 1) return;
154→    const idx = tabs.findIndex((t) => t.id === tabId);
155→    const newTabs = tabs.filter((t) => t.id !== tabId);
156→    setTabs(newTabs);
157→    if (activeTabId === tabId) {
158→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
159→    }
160→  }
161→
162→  function handleResizeStart(e: React.MouseEvent) {
163→    e.preventDefault();
164→    const startY = e.clientY;
