208→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
209→              {(["checkpoints", "diff"] as const).map((tab) => (
210→                <button
211→                  key={tab}
212→                  onClick={() => setInnerTab(tab)}
213→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
214→                    innerTab === tab
